 87→// Checkpointing starts a background worker that periodically saves metric data to disk.
 88→//
 89→// Checkpoints are written every 12 hours (hardcoded).
 90→//
 91→// Format behaviour:
 92→//   - "json": Periodic checkpointing every checkpointInterval
 93→//   - "wal":  Periodic binary snapshots + WAL rotation every checkpointInterval
 94→func Checkpointing(wg *sync.WaitGroup, ctx context.Context) {
 95→	lastCheckpointMu.Lock()
 96→	lastCheckpoint = time.Now()
 97→	lastCheckpointMu.Unlock()
 98→
 99→	ms := GetMemoryStore()
100→
101→	wg.Go(func() {
102→
103→		const checkpointInterval = 12 * time.Hour
104→		d := checkpointInterval
105→
106→		ticker := time.NewTicker(d)
107→		defer ticker.Stop()
108→
109→		for {
110→			select {
111→			case <-ctx.Done():
112→				return
113→			case <-ticker.C:
114→				lastCheckpointMu.Lock()
115→				from := lastCheckpoint
116→				lastCheckpointMu.Unlock()
117→
118→				now := time.Now()
119→				cclog.Infof("[METRICSTORE]> start checkpointing (starting at %s)...", from.Format(time.RFC3339))
120→
121→				if Keys.Checkpoints.FileFormat == "wal" {
122→					n, hostDirs, err := ms.ToCheckpointWAL(Keys.Checkpoints.RootDir, from.Unix(), now.Unix())
123→					if err != nil {
124→						cclog.Errorf("[METRICSTORE]> binary checkpointing failed: %s", err.Error())
125→					} else {
126→						cclog.Infof("[METRICSTORE]> done: %d binary snapshot files created", n)
127→						lastCheckpointMu.Lock()
128→						lastCheckpoint = now
129→						lastCheckpointMu.Unlock()
130→						// Rotate WAL files for successfully checkpointed hosts.
131→						RotateWALFiles(hostDirs)
132→					}
133→				} else {
134→					n, err := ms.ToCheckpoint(Keys.Checkpoints.RootDir, from.Unix(), now.Unix())
135→					if err != nil {
136→						cclog.Errorf("[METRICSTORE]> checkpointing failed: %s", err.Error())
137→					} else {
138→						cclog.Infof("[METRICSTORE]> done: %d checkpoint files created", n)
139→						lastCheckpointMu.Lock()
140→						lastCheckpoint = now
141→						lastCheckpointMu.Unlock()
142→					}
143→				}
144→			}
145→		}
146→	})
147→}
