149→// MarshalJSON provides optimized JSON encoding for CheckpointMetrics.
150→//
151→// Since schema.Float has custom MarshalJSON, serializing []Float has significant overhead.
152→// This method manually constructs JSON to avoid allocations and interface conversions.
153→func (cm *CheckpointMetrics) MarshalJSON() ([]byte, error) {
154→	buf := make([]byte, 0, 128+len(cm.Data)*8)
155→	buf = append(buf, `{"frequency":`...)
156→	buf = strconv.AppendInt(buf, cm.Frequency, 10)
157→	buf = append(buf, `,"start":`...)
158→	buf = strconv.AppendInt(buf, cm.Start, 10)
159→	buf = append(buf, `,"data":[`...)
160→	for i, x := range cm.Data {
161→		if i != 0 {
162→			buf = append(buf, ',')
163→		}
164→		if x.IsNaN() {
165→			buf = append(buf, `null`...)
166→		} else {
167→			buf = strconv.AppendFloat(buf, float64(x), 'f', 1, 32)
168→		}
169→	}
170→	buf = append(buf, `]}`...)
171→	return buf, nil
172→}
