174→// ToCheckpoint writes metric data to checkpoint files in parallel (JSON format).
175→//
176→// Metrics at root and cluster levels are skipped. One file per host is created.
177→// Uses worker pool (Keys.NumWorkers) for parallel processing. Only locks one host
178→// at a time, allowing concurrent writes/reads to other hosts.
179→//
180→// Returns the number of checkpoint files created and any errors encountered.
181→func (m *MemoryStore) ToCheckpoint(dir string, from, to int64) (int, error) {
182→	// Pre-calculate capacity by counting cluster/host pairs
183→	m.root.lock.RLock()
184→	totalHosts := 0
185→	for _, l1 := range m.root.children {
186→		l1.lock.RLock()
187→		totalHosts += len(l1.children)
188→		l1.lock.RUnlock()
189→	}
190→	m.root.lock.RUnlock()
191→
192→	levels := make([]*Level, 0, totalHosts)
193→	selectors := make([][]string, 0, totalHosts)
194→
195→	m.root.lock.RLock()
196→	for sel1, l1 := range m.root.children {
197→		l1.lock.RLock()
198→		for sel2, l2 := range l1.children {
199→			levels = append(levels, l2)
200→			selectors = append(selectors, []string{sel1, sel2})
201→		}
202→		l1.lock.RUnlock()
203→	}
204→	m.root.lock.RUnlock()
205→
206→	type workItem struct {
207→		level    *Level
208→		dir      string
209→		selector []string
210→	}
211→
212→	n, errs := int32(0), int32(0)
213→
214→	var wg sync.WaitGroup
215→	wg.Add(Keys.NumWorkers)
216→	work := make(chan workItem, Keys.NumWorkers*2)
217→	for worker := 0; worker < Keys.NumWorkers; worker++ {
218→		go func() {
219→			defer wg.Done()
220→
221→			for workItem := range work {
222→				if err := workItem.level.toCheckpoint(workItem.dir, from, to, m); err != nil {
223→					if err == ErrNoNewArchiveData {
224→						continue
225→					}
226→
227→					cclog.Errorf("[METRICSTORE]> error while checkpointing %#v: %s", workItem.selector, err.Error())
228→					atomic.AddInt32(&errs, 1)
229→				} else {
230→					atomic.AddInt32(&n, 1)
231→				}
232→			}
233→		}()
234→	}
235→
236→	for i := 0; i < len(levels); i++ {
237→		dir := path.Join(dir, path.Join(selectors[i]...))
238→		work <- workItem{
239→			level:    levels[i],
240→			dir:      dir,
241→			selector: selectors[i],
242→		}
243→	}
244→
245→	close(work)
246→	wg.Wait()
247→
248→	if errs > 0 {
249→		return int(n), fmt.Errorf("[METRICSTORE]> %d errors happened while creating checkpoints (%d successes)", errs, n)
250→	}
251→	return int(n), nil
252→}
