254→// toCheckpointFile recursively converts a Level tree to CheckpointFile structure.
255→// Skips metrics that are already archived. Returns nil if no unarchived data exists.
256→func (l *Level) toCheckpointFile(from, to int64, m *MemoryStore) (*CheckpointFile, error) {
257→	l.lock.RLock()
258→	defer l.lock.RUnlock()
259→
260→	retval := &CheckpointFile{
261→		From:     from,
262→		To:       to,
263→		Metrics:  make(map[string]*CheckpointMetrics),
264→		Children: make(map[string]*CheckpointFile),
265→	}
266→
267→	for metric, minfo := range m.Metrics {
268→		b := l.metrics[minfo.offset]
269→		if b == nil {
270→			continue
271→		}
272→
273→		allArchived := true
274→		b.iterFromTo(from, to, func(b *buffer) error {
275→			if !b.archived {
276→				allArchived = false
277→				return fmt.Errorf("stop") // Early termination signal
278→			}
279→			return nil
280→		})
281→
282→		if allArchived {
283→			continue
284→		}
285→
286→		data := make([]schema.Float, (to-from)/b.frequency+1)
287→		data, start, end, err := b.read(from, to, data)
288→		if err != nil {
289→			return nil, err
290→		}
291→
292→		for i := int((end - start) / b.frequency); i < len(data); i++ {
293→			data[i] = schema.NaN
294→		}
295→
296→		retval.Metrics[metric] = &CheckpointMetrics{
297→			Frequency: b.frequency,
298→			Start:     start,
299→			Data:      data,
300→		}
301→	}
302→
303→	for name, child := range l.children {
304→		val, err := child.toCheckpointFile(from, to, m)
305→		if err != nil {
306→			return nil, err
307→		}
308→
309→		if val != nil {
310→			retval.Children[name] = val
311→		}
312→	}
313→
314→	if len(retval.Children) == 0 && len(retval.Metrics) == 0 {
315→		return nil, nil
316→	}
317→
318→	return retval, nil
319→}
