321→// toCheckpoint writes a Level's data to a JSON checkpoint file.
322→// Creates directory if needed. Returns ErrNoNewArchiveData if nothing to save.
323→func (l *Level) toCheckpoint(dir string, from, to int64, m *MemoryStore) error {
324→	cf, err := l.toCheckpointFile(from, to, m)
325→	if err != nil {
326→		return err
327→	}
328→
329→	if cf == nil {
330→		return ErrNoNewArchiveData
331→	}
332→
333→	filepath := path.Join(dir, fmt.Sprintf("%d.json", from))
334→	f, err := os.OpenFile(filepath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, CheckpointFilePerms)
335→	if err != nil && os.IsNotExist(err) {
336→		err = os.MkdirAll(dir, CheckpointDirPerms)
337→		if err == nil {
338→			f, err = os.OpenFile(filepath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, CheckpointFilePerms)
339→		}
340→	}
341→	if err != nil {
342→		return err
343→	}
344→	defer f.Close()
345→
346→	bw := bufio.NewWriter(f)
347→	if err = json.NewEncoder(bw).Encode(cf); err != nil {
348→		return err
349→	}
350→
351→	return bw.Flush()
352→}
353→
354→// enqueueCheckpointHosts traverses checkpoint directory and enqueues cluster/host pairs.
355→// Returns error if directory structure is invalid.
356→func enqueueCheckpointHosts(dir string, work chan<- [2]string) error {
357→	clustersDir, err := os.ReadDir(dir)
358→	if err != nil {
359→		return err
360→	}
361→
362→	for _, clusterDir := range clustersDir {
363→		if !clusterDir.IsDir() {
364→			return errors.New("[METRICSTORE]> expected only directories at first level of checkpoints/ directory")
365→		}
366→
367→		hostsDir, err := os.ReadDir(filepath.Join(dir, clusterDir.Name()))
368→		if err != nil {
369→			return err
370→		}
371→
372→		for _, hostDir := range hostsDir {
373→			if !hostDir.IsDir() {
374→				return errors.New("[METRICSTORE]> expected only directories at second level of checkpoints/ directory")
375→			}
376→
377→			work <- [2]string{clusterDir.Name(), hostDir.Name()}
378→		}
379→	}
380→
381→	return nil
382→}
383→
384→// FromCheckpoint loads checkpoint files from disk into memory in parallel.
385→//
386→// Uses worker pool to load cluster/host combinations. Returns number of files
387→// loaded and any errors.
388→func (m *MemoryStore) FromCheckpoint(dir string, from int64) (int, error) {
389→	var wg sync.WaitGroup
390→	work := make(chan [2]string, Keys.NumWorkers*4)
391→	n, errs := int32(0), int32(0)
392→
393→	wg.Add(Keys.NumWorkers)
394→	for worker := 0; worker < Keys.NumWorkers; worker++ {
395→		go func() {
396→			defer wg.Done()
397→			for host := range work {
398→				lvl := m.root.findLevelOrCreate(host[:], len(m.Metrics))
399→				nn, err := lvl.fromCheckpoint(m, filepath.Join(dir, host[0], host[1]), from)
400→				if err != nil {
401→					cclog.Errorf("[METRICSTORE]> error while loading checkpoints for %s/%s: %s", host[0], host[1], err.Error())
402→					atomic.AddInt32(&errs, 1)
403→				}
404→				atomic.AddInt32(&n, int32(nn))
405→			}
406→		}()
407→	}
408→
409→	err := enqueueCheckpointHosts(dir, work)
410→	close(work)
411→	wg.Wait()
412→
413→	if err != nil {
414→		return int(n), err
415→	}
416→
417→	if errs > 0 {
418→		return int(n), fmt.Errorf("[METRICSTORE]> %d errors happened while creating checkpoints (%d successes)", errs, n)
419→	}
420→	return int(n), nil
421→}
422→
423→// FromCheckpointFiles is the main entry point for loading checkpoints at startup.
424→//
425→// Creates checkpoint directory if it doesn't exist. This function must be called
426→// before any writes or reads, and can only be called once.
427→func (m *MemoryStore) FromCheckpointFiles(dir string, from int64) (int, error) {
428→	if _, err := os.Stat(dir); os.IsNotExist(err) {
429→		err := os.MkdirAll(dir, CheckpointDirPerms)
430→		if err != nil {
431→			cclog.Fatalf("[METRICSTORE]> Error creating directory: %#v\n", err)
432→		}
433→		cclog.Debugf("[METRICSTORE]> %#v Directory created successfully", dir)
434→	}
435→
436→	return m.FromCheckpoint(dir, from)
437→}
438→
439→func (l *Level) loadJSONFile(m *MemoryStore, f *os.File, from int64) error {
440→	br := bufio.NewReader(f)
441→	cf := &CheckpointFile{}
442→	if err := json.NewDecoder(br).Decode(cf); err != nil {
443→		return err
444→	}
445→
446→	if cf.To != 0 && cf.To < from {
447→		return nil
448→	}
449→
450→	if err := l.loadFile(cf, m); err != nil {
451→		return err
452→	}
453→
454→	return nil
455→}
456→
457→func (l *Level) loadFile(cf *CheckpointFile, m *MemoryStore) error {
458→	for name, metric := range cf.Metrics {
459→		n := len(metric.Data)
460→		b := &buffer{
461→			frequency: metric.Frequency,
462→			start:     metric.Start,
463→			data:      metric.Data[0:n:n],
464→			prev:      nil,
465→			next:      nil,
466→			archived:  true,
467→		}
468→
469→		minfo, ok := m.Metrics[name]
470→		if !ok {
471→			continue
472→		}
473→
474→		prev := l.metrics[minfo.offset]
475→		if prev == nil {
476→			l.metrics[minfo.offset] = b
477→		} else {
478→			if prev.start > b.start {
479→				return fmt.Errorf("[METRICSTORE]> buffer start time %d is before previous buffer start %d", b.start, prev.start)
480→			}
481→
482→			b.prev = prev
483→			prev.next = b
484→		}
485→		l.metrics[minfo.offset] = b
486→	}
487→
488→	if len(cf.Children) > 0 && l.children == nil {
489→		l.children = make(map[string]*Level)
490→	}
491→
492→	for sel, childCf := range cf.Children {
493→		child, ok := l.children[sel]
494→		if !ok {
495→			child = &Level{
496→				metrics:  make([]*buffer, len(m.Metrics)),
497→				children: nil,
498→			}
499→			l.children[sel] = child
500→		}
501→
502→		if err := child.loadFile(childCf, m); err != nil {
503→			return err
504→		}
505→	}
506→
507→	return nil
508→}
509→
510→// fromCheckpoint loads all checkpoint files (JSON, binary snapshot, WAL) for a
511→// single host directory. Snapshot files are loaded first (sorted by timestamp),
512→// then current.wal is replayed on top.
513→func (l *Level) fromCheckpoint(m *MemoryStore, dir string, from int64) (int, error) {
514→	direntries, err := os.ReadDir(dir)
515→	if err != nil {
516→		if os.IsNotExist(err) {
517→			return 0, nil
518→		}
519→		return 0, err
520→	}
521→
522→	allFiles := make([]fs.DirEntry, 0)
523→	var walEntry fs.DirEntry
524→	filesLoaded := 0
525→
526→	for _, e := range direntries {
527→		if e.IsDir() {
528→			// Legacy: skip subdirectories (only used by old Avro format).
529→			// These are ignored; their data is not loaded.
530→			cclog.Debugf("[METRICSTORE]> skipping subdirectory %s in checkpoint dir %s", e.Name(), dir)
531→			continue
532→		}
533→
534→		name := e.Name()
535→		if strings.HasSuffix(name, ".json") || strings.HasSuffix(name, ".bin") {
536→			allFiles = append(allFiles, e)
537→		} else if name == "current.wal" {
538→			walEntry = e
539→		}
540→		// Silently ignore other files (e.g., .tmp, .bin.tmp from interrupted writes).
541→	}
542→
543→	files, err := findFiles(allFiles, from, true)
544→	if err != nil {
545→		return filesLoaded, err
546→	}
547→
548→	loaders := map[string]func(*MemoryStore, *os.File, int64) error{
549→		".json": l.loadJSONFile,
550→		".bin":  l.loadBinaryFile,
551→	}
552→
553→	for _, filename := range files {
554→		ext := filepath.Ext(filename)
555→		loader := loaders[ext]
556→		if loader == nil {
557→			cclog.Warnf("[METRICSTORE]> unknown extension for checkpoint file %s", filename)
558→			continue
559→		}
560→
561→		err := func() error {
562→			f, err := os.Open(path.Join(dir, filename))
563→			if err != nil {
564→				return err
565→			}
566→			defer f.Close()
567→			return loader(m, f, from)
568→		}()
569→		if err != nil {
570→			return filesLoaded, err
571→		}
572→		filesLoaded++
573→	}
574→
575→	// Replay WAL after all snapshot files so it fills in data since the last snapshot.
576→	if walEntry != nil {
577→		err := func() error {
578→			f, err := os.Open(path.Join(dir, walEntry.Name()))
579→			if err != nil {
580→				return err
581→			}
582→			defer f.Close()
583→			return l.loadWALFile(m, f, from)
584→		}()
585→		if err != nil {
586→			// WAL errors are non-fatal: the snapshot already loaded the bulk of data.
587→			cclog.Warnf("[METRICSTORE]> WAL replay error for %s: %v (data since last snapshot may be missing)", dir, err)
588→		} else {
589→			filesLoaded++
590→		}
591→	}
592→
593→	return filesLoaded, nil
594→}
595→
596→// parseTimestampFromFilename extracts a Unix timestamp from a checkpoint filename.
597→// Supports ".json" (format: "<ts>.json") and ".bin" (format: "<ts>.bin").
598→func parseTimestampFromFilename(name string) (int64, error) {
599→	switch {
600→	case strings.HasSuffix(name, ".json"):
601→		return strconv.ParseInt(name[:len(name)-5], 10, 64)
602→	case strings.HasSuffix(name, ".bin"):
603→		return strconv.ParseInt(name[:len(name)-4], 10, 64)
604→	default:
605→		return 0, fmt.Errorf("unknown checkpoint extension for file %q", name)
606→	}
607→}
608→
609→// findFiles returns filenames from direntries whose timestamps satisfy the filter.
610→// If findMoreRecentFiles is true, returns files with timestamps >= t (plus the
611→// last file before t if t falls between two files).
612→func findFiles(direntries []fs.DirEntry, t int64, findMoreRecentFiles bool) ([]string, error) {
613→	nums := map[string]int64{}
614→	for _, e := range direntries {
615→		name := e.Name()
616→		if !strings.HasSuffix(name, ".json") && !strings.HasSuffix(name, ".bin") {
617→			continue
618→		}
619→
620→		ts, err := parseTimestampFromFilename(name)
621→		if err != nil {
622→			return nil, err
623→		}
624→		nums[name] = ts
625→	}
626→
627→	sort.Slice(direntries, func(i, j int) bool {
628→		a, b := direntries[i], direntries[j]
629→		return nums[a.Name()] < nums[b.Name()]
630→	})
631→
632→	if len(nums) == 0 {
633→		return nil, nil
634→	}
635→
636→	filenames := make([]string, 0)
637→
638→	for i, e := range direntries {
639→		ts1 := nums[e.Name()]
640→
641→		if findMoreRecentFiles && t <= ts1 {
642→			filenames = append(filenames, e.Name())
643→		} else if !findMoreRecentFiles && ts1 <= t && ts1 != 0 {
644→			filenames = append(filenames, e.Name())
645→		}
646→
647→		if i == len(direntries)-1 {
648→			continue
649→		}
650→
651→		enext := direntries[i+1]
652→		ts2 := nums[enext.Name()]
653→
654→		if findMoreRecentFiles {
655→			if ts1 < t && t < ts2 {
656→				filenames = append(filenames, e.Name())
657→			}
658→		}
659→	}
660→
661→	return filenames, nil
662→}
